import{_ as n,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F03: 合約負債與營收能見度","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F03_合約負債與營收能見度_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F03_合約負債與營收能見度_財務分析專家.md"}'),r={name:"32Ｑ題本＿重要/財務組/F03_合約負債與營收能見度_財務分析專家.md"};function e(a,o,s,c,g,d){return t(),i("div",null,[...o[0]||(o[0]=[l('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f03-合約負債與營收能見度" tabindex="-1">F03: 合約負債與營收能見度 <a class="header-anchor" href="#f03-合約負債與營收能見度" aria-label="Permalink to &quot;F03: 合約負債與營收能見度&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F03</li><li><strong>題目：</strong> 合約負債與未來收入的變動關係為何？訂單轉化為實質營收的速度是否出現停滯？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「收入認列準則 (IFRS 15)」與「收入建模 (Revenue Modeling)」。能從「合約負債 (Contract Liabilities)」科目中精準讀取訂單能見度、客戶預付款意願，並能透視「虛假訂單」風險，是預判未來營收動能的權威學家。</li><li><strong>意圖：</strong> 執行「營收領先指標審核」。透過測算「合約負債」與「現行營收」的比例關係及轉化時間，判定企業未來的業績爆發力與營運動能的「含金量」，識別潛在的退單或訂單去化停滯風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>： <ul><li>調用 <code>TaiwanStockBalanceSheet</code> 提取 <code>CurrentContractLiabilities</code> (流動合約負債) 之歷史季度數據。</li><li>這是審計「訂單能見度」的最上位物理證據。</li></ul></li><li><strong>【外部驗證：法說會/重大訊息】</strong>：透過 Web Search 檢索「[公司名] 接單 展望」、「合約負債 變動說明」。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱 <code>財務報告附註 -&gt; 收入認列會計政策</code> 及 <code>重要合約揭露</code>。獲取訂單履行之關鍵條件。</li></ol></li><li><strong>邏輯：</strong> 執行「訂單轉化效率算則」——對比合約負債季成長率與次季營收現實值；執行「能見度週期外推」——根據數據判定未來 1-2 季營收的確定性。</li><li><strong>來源：</strong> <code>FinMind (資產負債表)</code>, <code>年度報告 (營收認列政策)</code>, <code>法說會會議紀錄 (訂單展望數據)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py balance_sheet [股號]</code> → 抓 <code>CurrentContractLiabilities</code>（合約負債）</li><li><strong>取營收</strong>：<code>python3 數據採集器.py finance [股號]</code> → 抓 <code>Revenue</code>，對比合約負債變化</li><li><strong>判讀能見度</strong>：合約負債 / 季度營收 = 營收能見天數。&gt;50% = 高能見度，&lt;20% = 低能見度</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具從年報提取「合約負債明細」確認主要客戶訂單</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【合約負債現狀核實】</strong>：智慧體<strong>必須</strong>執行自最新年度 $Y$ 溯回至 $Y-3$ 之四年度財務對比分析，列出最近四個季度的「合約負債」金額及其佔營收之百分比。嚴禁進行無數據支撐的「前景看好」評論。</li><li><strong>【訂單動能定量測算】</strong>：計算「合約負債變動率」與「營收變動率」的彈性。若合約負債大幅萎縮，必須發出「未來營收動能枯竭」之風險警告。</li><li><strong>【轉化速度壓力測試】</strong>：測算「合約負債 / 日平均營收」比值（預估能見天數）。若該天數異常縮短，智慧體必須判定為「訂單去化過快而新單銜接不足」之風險。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：<strong>絕對禁用</strong>「模擬」、「預測」、「滿手訂單」。必須使用「根據數據測算顯示」、「訂單能見度趨勢外推」、「合約負債轉換效率分析」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f03-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F03 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f03-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F03 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「指標變動+動能判定」結構（例：合約負債成長 X%，訂單能見度 Y 季，判定未來營收能見度 [明確/模糊]，營收動能處於 [擴張期/衰退期]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：合約負債持續增長且轉化為營收的速度加快，顯示訂單獲取能力極強且下游去化順暢。</li><li><strong>A (良)</strong>：合約負債保持穩定，訂單能見度維持在安全水位，業務展望清晰。</li><li><strong>B (持平)</strong>：合約負債大幅萎縮或轉化天數異常拉長（超過 2 季無營收轉換），預示未來營收可能出現斷崖式下滑或面臨客戶退單風險。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>訂單領先指標 (Leading Indicator)</strong>：分析合約負債與歷史營收趨勢的過往軌跡對應。</li><li><strong>含金量分析 (Order Quality)</strong>：評估預收款項是否來自高品質、且無退單疑慮的長期客戶。</li><li><strong>產業對位 (Industry Context)</strong>：對比同業（如建商、半導體設備、雲端服務）的平均合約負債水位。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind 季度數據與對應之資產負債表科目標示。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「長期合約」與「短期合約」的配比。在景氣下行時，合約負債的萎縮是裁員或縮減開支的最早期訊號。專家應在此處穿透營收轉化效率，並給出關於未來業績確定性的實質診斷。</li></ul>',11)])])}const h=n(r,[["render",e]]);export{u as __pageData,h as default};
